import React, { useEffect, useMemo, useState } from 'react'
import { css } from '@linaria/core'
import zionDebug from '@fs/zion-debug'
import { boolAttr } from '@fs/zion-frontend-friends'
import { ContentCheck, MenuSearch, MenuFilter, ContentFlag, ArrowChange, NoticeWarning } from '@fs/zion-icon'
import { useSplitManager } from '@splitsoftware/splitio-react'
import {
  Button,
  Paragraph,
  Ellipsis,
  TextField,
  Row,
  IconButton,
  LabelTooltip,
  ListItem,
  MenuOverlay,
  Toggle,
  ResponsiveTable,
  ResponsiveTableRow,
  Select,
  colors,
  useOverlay,
  H5,
} from '@fs/zion-ui'
import { SupplementalOverlay } from '@fs/zion-ui/quarks-authorized-use-only'
import type { Flag, Flags } from '@fs/flags-js'
import { useFeatureFlags, type FlagOverrideHandlers } from '@fs/zion-flags'

type FlagType = 'BOOLEAN' | 'MULTI' | 'UNKNOWN'

const debug = zionDebug('zion:flags:overrides')

export default function FlagOverridesUi({
  flagOverrides,
  flagOverrideHandlers,
  hideAdminOverlay = false, // for Zion storybook
  inLocalhostMode = false,
  onClose, // for Zion storybook; run if the overlay is closed (note: may run more than once)
  showOverrides = false, // for Zion storybook or to immediately show the overlay without requiring a button click
}: {
  flagOverrides: Flags | undefined
  flagOverrideHandlers: FlagOverrideHandlers
  hideAdminOverlay?: boolean
  inLocalhostMode?: boolean
  onClose?: () => void
  showOverrides?: boolean
}): JSX.Element {
  const overlay = useOverlay({ initiallyOpen: showOverrides })
  const [renderDialog, setRenderDialog] = useState(showOverrides) // don't render the overlay until the button is clicked at least once
  const { manager } = useSplitManager()
  const splits = manager?.splits() ?? []

  const flags = useFeatureFlags(splits.map(({ name }) => name))
  const { removeAll } = flagOverrideHandlers
  const { close, isOpen, transitioning } = overlay

  useEffect(() => {
    if (hideAdminOverlay) {
      if (showOverrides && !isOpen && !transitioning) {
        setRenderDialog(true)
        overlay.open()
      } else if (!showOverrides && isOpen && !transitioning) {
        overlay.close()
      }
    }
    if (!isOpen && transitioning) {
      // The overlay is currently exiting (still transitioning out)
      // Tell Zion storybook the window has closed so it can change the icon
      onClose && onClose()
    }
  }, [hideAdminOverlay, isOpen, onClose, overlay, showOverrides, transitioning])

  debug('Rendering override panel', splits, flags)
  return (
    <>
      {!hideAdminOverlay && (
        <FlagAdminOverlay
          inLocalhostMode={inLocalhostMode}
          overrideCount={Object.keys(flagOverrides || []).length}
          onClick={(e) => {
            setRenderDialog(true)
            overlay.handleClick(e)
          }}
        />
      )}
      {renderDialog && (
        <SupplementalOverlay
          overlayKey="flagOverlay"
          {...overlay}
          header="Feature Flags"
          footer={
            <Row alignX="end" alignY="middle">
              <LabelTooltip
                target={<NoticeWarning size="sm" color={colors.red50} />}
                label="Flag values may be incorrect if the flag has rules that rely on custom attributes"
                growX
              />

              <Button onClick={removeAll}>Reset All</Button>
              <Button onClick={close} emphasis="high">
                Close
              </Button>
            </Row>
          }
          defaultWidth={500}
          defaultHeight={800}
        >
          <FlagOverrideList
            splits={splits}
            flagOverrides={flagOverrides}
            flags={flags}
            flagOverrideHandlers={flagOverrideHandlers}
          />
        </SupplementalOverlay>
      )}
    </>
  )
}

const flagOverlayCss = css`
  position: fixed;
  bottom: 70px;
  height: 40px;
  width: 32px;
  background: ${colors.yellow05};
  color: ${colors.gray100};
  border: none;
  border-start-end-radius: 5px;
  border-end-end-radius: 5px;
  box-shadow: 0 3px 10px rgb(0 0 0 / 0.2);
  z-index: 2;
  cursor: pointer;
  &:hover {
    box-shadow: 0 3px 10px rgb(0 0 0 / 0.3);
  }
  &:focus-visible {
    outline: 3px solid ${colors.blue60};
  }
  [data-localhost]& {
    background: ${colors.blue05};
  }

  @media screen and (max-width: 50em) {
    position: absolute;
    top: 20px;
  }

  @media print {
    display: none;
  }
`

const overrideCountCss = css`
  position: absolute;
  font-size: 10px;
  bottom: 4px;
  inset-inline-end: 4px;
`

const flagIconCss = css`
  position: absolute;
  top: 8px;
  inset-inline-start: 3px;
`

const preCss = css`
  font-size: 12px;
  margin: 0;
  margin-inline-start: 48px;
`

function FlagAdminOverlay({
  overrideCount,
  inLocalhostMode,
  onClick,
}: {
  overrideCount: number
  inLocalhostMode: boolean
  onClick: (e) => void
}): JSX.Element {
  return (
    <button
      aria-label="Open Flag Overrides"
      type="button"
      onClick={onClick}
      className={flagOverlayCss}
      data-localhost={boolAttr(inLocalhostMode)}
    >
      <div className={flagIconCss}>
        <ContentFlag role="none" />
      </div>
      {overrideCount > 0 && (
        <div aria-label="Override Count" className={overrideCountCss}>
          {overrideCount}
        </div>
      )}
    </button>
  )
}

const checked = <ListItem.Icon Icon={ContentCheck} />
const unchecked = <ListItem.Filler />

function FlagOverrideList({
  splits,
  flagOverrides,
  flags,
  flagOverrideHandlers,
}: {
  splits: SplitIO.SplitViews
  flagOverrides: Flags | undefined
  flags: Flags
  flagOverrideHandlers: FlagOverrideHandlers
}): JSX.Element {
  const [searchFilter, setSearchFilter] = useState('')
  const [filterOverridden, setFilterOverridden] = useState(false)
  const overriddenSplits = splits.filter((split) => flagOverrides?.[split.name])

  const splitsToShow = useMemo(() => {
    return (filterOverridden ? overriddenSplits : splits)
      ?.filter((s) => s.name.toLowerCase().includes(searchFilter.toLowerCase()))
      .sort((a, b) => a.name.localeCompare(b.name))
  }, [filterOverridden, overriddenSplits, searchFilter, splits])
  const hasNonBoolean = splitsToShow.find((split) => !isTypeOnOff(split))

  const nameColumnSm = hasNonBoolean ? 8 : 9
  const nameColumnLg = hasNonBoolean ? 9 : 10
  const nameColumnXl = hasNonBoolean ? 10 : 11

  return (
    <>
      <Row>
        <TextField
          growX
          clearable
          onClear={() => setSearchFilter('')}
          value={searchFilter}
          onChange={({ target }) => setSearchFilter(target.value)}
          Icon={MenuSearch}
          aria-label="Search feature flags by name"
        />
        <MenuOverlay menuButton={<IconButton title="Filter Results" Icon={MenuFilter} />}>
          <ListItem
            primaryText="All Flags"
            startElement={filterOverridden ? unchecked : checked}
            onClick={() => setFilterOverridden(false)}
          />
          <ListItem
            primaryText="Overridden Flags"
            startElement={filterOverridden ? checked : unchecked}
            onClick={() => setFilterOverridden(true)}
          />
        </MenuOverlay>
      </Row>
      {splitsToShow.length ? (
        <ResponsiveTable
          verticalAlign="middle"
          totalColumnCount={3}
          atSizeColumns={{
            default: { labels: ['', 'Name & Treatment'], columnWidths: [3, 9] },
            xxs: { labels: ['', 'Name & Treatment'], columnWidths: [2, 10] },
            sm: { labels: ['', 'Name', 'Treatment'], columnWidths: ['48px', nameColumnSm, 12 - nameColumnSm] },
            lg: { labels: ['', 'Name', 'Treatment'], columnWidths: ['48px', nameColumnLg, 12 - nameColumnLg] },
            xl: { labels: ['', 'Name', 'Treatment'], columnWidths: ['48px', nameColumnXl, 12 - nameColumnXl] },
          }}
          gutters="xxs"
        >
          {splitsToShow.map(
            (bananaSplit) =>
              flags[bananaSplit.name] && (
                <FlagOverrideControl
                  key={bananaSplit.name}
                  split={bananaSplit}
                  isOverridden={!!flagOverrides?.[bananaSplit.name]}
                  flag={flags[bananaSplit.name]}
                  flagOverrideHandlers={flagOverrideHandlers}
                />
              )
          )}
        </ResponsiveTable>
      ) : (
        <>
          <H5>Sorry, no flags found ...</H5>
          <Paragraph size="sm">Try refining your search and try again</Paragraph>
        </>
      )}
    </>
  )
}

function FlagOverrideControl({
  split,
  isOverridden,
  flag,
  flagOverrideHandlers,
}: {
  split: SplitIO.SplitView
  isOverridden: boolean
  flag: Flag<unknown>
  flagOverrideHandlers: FlagOverrideHandlers
}): JSX.Element {
  const { add, remove } = flagOverrideHandlers
  const treatmentOptions = split.treatments.map((treatment) => ({ value: treatment, label: treatment }))

  function handleReset(): void {
    debug('remove override', split.name)
    remove(split.name)
  }

  function updateOverride(newTreatment: string): void {
    add(split.name, {
      treatment: newTreatment,
      config: split.configs[newTreatment] ? JSON.parse(split.configs[newTreatment]) : null,
    })
  }

  function handleToggleClick(): void {
    const newValue = flag.treatment === 'on' ? 'off' : 'on'
    updateOverride(newValue)
  }

  function handleChange(e: { target: { value: string } }): void {
    updateOverride(e.target.value)
  }

  function renderTreatmentControl(): JSX.Element {
    switch (typeOfSplit(split)) {
      case 'BOOLEAN':
        return <Toggle onChange={handleToggleClick} checked={flag.treatment === 'on'} label={`"${flag.treatment}"`} />
      case 'MULTI':
        return <Select options={treatmentOptions} value={flag.treatment} onChange={handleChange} hidePlaceholder />
      default:
        return <TextField value={flag.treatment} onChange={handleChange} />
    }
  }
  return (
    <ResponsiveTableRow
      column1={isOverridden ? <IconButton Icon={ArrowChange} onClick={handleReset} title="Reset" /> : null}
      column2={<Ellipsis>{isOverridden ? <strong>{split.name}</strong> : split.name}</Ellipsis>}
      column3={renderTreatmentControl()}
    >
      {flag?.config && (
        <pre className={preCss} id={`config-${split.name}`}>
          {JSON.stringify(flag.config, undefined, 2)}
        </pre>
      )}
    </ResponsiveTableRow>
  )
}

function typeOfSplit(split): FlagType {
  if (isTypeOnOff(split)) return 'BOOLEAN'
  if (split.treatments.length > 1) return 'MULTI'
  return 'UNKNOWN'
}

function isTypeOnOff(split): boolean {
  const booleanOptions = ['on', 'off']
  let isOnOff =
    booleanOptions
      .filter((x) => !split.treatments.includes(x))
      .concat(split.treatments.filter((x) => !booleanOptions.includes(x))).length === 0
  // To support mockFlags, if the treatment has just one value and it's either 'on' or 'off', then treat it as boolean
  if (split.treatments.length === 1 && booleanOptions.includes(split.treatments[0])) isOnOff = true
  return isOnOff
}
